import json
import re

def clean_id(id_string):
    if isinstance(id_string, str):
        return re.sub(r'[^a-zA-Z0-9]', '', id_string).strip()
    return id_string

case_id_raw = '500Wt00000DDyznIAD'
cleaned_case_id = clean_id(case_id_raw)

print("__RESULT__:")
print(json.dumps(cleaned_case_id))

